Read /worksp/popdam/src/types/assets.ts.

Then EDIT the file to ADD the following new type after the existing LibraryMode type:

export type CardStyle = "gallery" | "editorial" | "compact";

Also update the EXISTING SortField type to add the groups-specific sorts. Currently it is:
  export type SortField = "modified_at" | "file_created_at" | "filename" | "file_size";

Change it to:
  export type SortField = "modified_at" | "file_created_at" | "filename" | "file_size" | "sku" | "asset_count";

These new sort fields are for style groups mode (sku A-Z, file count).

Write the minimal targeted edit using the Edit tool.

content.content:
1	import type { Tables } from "@/integrations/supabase/types";
2	
3	export type Asset = Tables<"assets">;
4	
5	export type SortField = "modified_at" | "file_created_at" | "filename" | "file_size";
6	export type SortDirection = "asc" | "desc";
7	export type ViewMode = "grid" | "list";
8	export type LibraryMode = "groups" | "assets";
9	
10	export type FileStatusFilter = "has_preview" | "no_preview_renderable" | "no_pdf_compat" | "no_preview_unsupported";
11	
12	export interface AssetFilters {
13	  search: string;
14	  fileType: string[];
15	  status: string[];
16	  workflowStatus: string[];
17	  isLicensed: boolean | null;
18	  licensorId: string | null;
19	  propertyId: string | null;
20	  assetType: string[];
21	  artSource: string[];
22	  tagFilter: string;
23	  fileStatus: FileStatusFilter[];
24	  productCategory: string[];
25	  /** Pipeline stage inferred from the folder under "____New Structure" (multi-select) */
26	  stage: string[];
27	  /** Customer inferred from the folder path (single-select) */
28	  customer: string | null;
29	  /** Customer program inferred from the folder path (single-select) */
30	  program: string | null;
31	}
32	
33	/** Pipeline stages, as named by the NAS folder tree under "____New Structure". */
34	export const STAGE_OPTIONS = [
35	  "In Development",
36	  "Concept Approved Designs",
37	  "Product Ideas",
38	  "Freelancer art",
39	  "Discontinued",
40	] as const;
41	
42	export const defaultFilters: AssetFilters = {
43	  search: "",
44	  fileType: [],
45	  status: [],
46	  workflowStatus: [],
47	  isLicensed: null,
48	  licensorId: null,
49	  propertyId: null,
50	  assetType: [],
51	  artSource: [],
52	  tagFilter: "",
53	  fileStatus: [],
54	  productCategory: [],
55	  stage: [],
56	  customer: null,
57	  program: null,
58	};
59	
60	export interface FacetCounts {
61	  fileType: Record<string, number>;
62	  status: Record<string, number>;
63	  workflowStatus: Record<string, number>;
64	  isLicensed: { true: number; false: number };
65	  stage: Record<string, number>;
66	}
67	
68	export function hasActiveFilters(filters: AssetFilters): boolean {
69	  return (
70	    filters.search !== "" ||
71	    filters.fileType.length > 0 ||
72	    filters.status.length > 0 ||
73	    filters.workflowStatus.length > 0 ||
74	    filters.isLicensed !== null ||
75	    filters.licensorId !== null ||
76	    filters.propertyId !== null ||
77	    filters.assetType.length > 0 ||
78	    filters.artSource.length > 0 ||
79	    filters.tagFilter !== "" ||
80	    filters.fileStatus.length > 0 ||
81	    filters.productCategory.length > 0 ||
82	    filters.stage.length > 0 ||
83	    filters.customer !== null ||
84	    filters.program !== null
85	  );
86	}
87	
88	export function countActiveFilters(filters: AssetFilters): number {
89	  let count = 0;
90	  if (filters.fileType.length > 0) count++;
91	  if (filters.status.length > 0) count++;
92	  if (filters.workflowStatus.length > 0) count++;
93	  if (filters.isLicensed !== null) count++;
94	  if (filters.licensorId) count++;
95	  if (filters.propertyId) count++;
96	  if (filters.assetType.length > 0) count++;
97	  if (filters.artSource.length > 0) count++;
98	  if (filters.tagFilter) count++;
99	  if (filters.fileStatus.length > 0) count++;
100	  if (filters.productCategory.length > 0) count++;
101	  if (filters.stage.length > 0) count++;
102	  if (filters.customer) count++;
103	  if (filters.program) count++;
104	  return count;
105	}
